const client = $json;
const timezone = client.timezone || 'America/Sao_Paulo';

function dateInZone(date, timeZone) {
  const parts = new Intl.DateTimeFormat('en-CA', {
    timeZone,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
  }).formatToParts(date);
  const map = Object.fromEntries(parts.map((p) => [p.type, p.value]));
  return `${map.year}-${map.month}-${map.day}`;
}

function previousDate(isoDate) {
  const [year, month, day] = isoDate.split('-').map(Number);
  return new Date(Date.UTC(year, month - 1, day) - 86400000)
    .toISOString()
    .slice(0, 10);
}

function normalizeArray(value, fallback = []) {
  if (Array.isArray(value)) return value;
  if (value === null || value === undefined || value === '') return fallback;
  return String(value)
    .replace(/[{}]/g, '')
    .split(',')
    .map((v) => v.trim().replace(/^"|"$/g, ''))
    .filter(Boolean);
}

const today = dateInZone(new Date(), timezone);
const yesterday = previousDate(today);
const adAccountId = String(client.ad_account_id || '').replace(/^act_/, '');

return [{
  json: {
    ...client,
    ad_account_id: adAccountId,
    report_date: today,
    today,
    yesterday,
    conversion_action_types: normalizeArray(
      client.conversion_action_types,
      ['lead', 'onsite_conversion.messaging_conversation_started_7d']
    ),
    attribution_windows: normalizeArray(
      client.attribution_windows,
      ['7d_click', '1d_view']
    ),
  },
}];

const client = $('Preparar Datas').item.json;
const todayResponse = $('Meta ads - Hoje').item.json;
const yesterdayResponse = $('Meta ads - Ontem').item.json;

function unwrap(response) {
  if (!response) return { data: [], error: { message: 'Resposta vazia da API' } };
  if (response.error) return { data: [], error: response.error };
  return response;
}

function firstRow(response) {
  const payload = unwrap(response);
  if (payload.error) return { row: {}, error: payload.error };
  return { row: Array.isArray(payload.data) && payload.data.length ? payload.data[0] : {}, error: null };
}

function number(value) {
  const parsed = Number(value ?? 0);
  return Number.isFinite(parsed) ? parsed : 0;
}

function sumActionTypes(list, actionTypes) {
  if (!Array.isArray(list)) return 0;
  const accepted = new Set(actionTypes || []);
  return list.reduce((total, entry) => {
    return accepted.has(entry.action_type) ? total + number(entry.value) : total;
  }, 0);
}

function findActionValue(list, actionTypes) {
  if (!Array.isArray(list)) return 0;
  const accepted = new Set(actionTypes || []);
  return list.reduce((total, entry) => {
    return accepted.has(entry.action_type) ? total + number(entry.value) : total;
  }, 0);
}

function firstNumericArrayValue(list, preferredTypes = []) {
  if (!Array.isArray(list)) return 0;
  for (const type of preferredTypes) {
    const found = list.find((entry) => entry.action_type === type);
    if (found) return number(found.value);
  }
  return list.length ? number(list[0].value) : 0;
}

function variation(current, previous) {
  if (previous === 0 && current === 0) return { value: 0, label: '0,0%' };
  if (previous === 0) return { value: null, label: 'novo/sem base' };
  const value = ((current - previous) / Math.abs(previous)) * 100;
  const sign = value > 0 ? '+' : '';
  return {
    value,
    label: `${sign}${value.toLocaleString('pt-BR', {
      minimumFractionDigits: 1,
      maximumFractionDigits: 1,
    })}%`,
  };
}

function formatCurrency(value, currency) {
  try {
    return new Intl.NumberFormat('pt-BR', {
      style: 'currency',
      currency: currency || 'BRL',
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    }).format(number(value));
  } catch {
    return `R$ ${number(value).toFixed(2).replace('.', ',')}`;
  }
}

function formatNumber(value, decimals = 0) {
  return number(value).toLocaleString('pt-BR', {
    minimumFractionDigits: decimals,
    maximumFractionDigits: decimals,
  });
}

function extractMetrics(row) {
  const spend = number(row.spend);
  const impressions = number(row.impressions);
  const reach = number(row.reach);
  const clicks = number(row.clicks);
  const ctr = number(row.ctr);
  const cpc = number(row.cpc);
  const cpm = number(row.cpm);
  const conversions = sumActionTypes(row.actions, client.conversion_action_types);
  const conversionValue = findActionValue(row.action_values, [
    'purchase',
    'omni_purchase',
    'offsite_conversion.fb_pixel_purchase',
    'offsite_conversion.custom.%',
  ]);
  const apiRoas = firstNumericArrayValue(row.purchase_roas, [
    'omni_purchase',
    'offsite_conversion.fb_pixel_purchase',
  ]);
  const roas = apiRoas || (spend > 0 ? conversionValue / spend : 0);
  const costPerResult = conversions > 0 ? spend / conversions : 0;

  return {
    spend,
    impressions,
    reach,
    clicks,
    ctr,
    cpc,
    cpm,
    conversions,
    cost_per_result: costPerResult,
    conversion_value: conversionValue,
    roas,
    date_start: row.date_start || null,
    date_stop: row.date_stop || null,
  };
}

const todayPayload = firstRow(todayResponse);
const yesterdayPayload = firstRow(yesterdayResponse);

const apiError = todayPayload.error || yesterdayPayload.error;
const supportedChannel = ['whatsapp', 'email'].includes(String(client.channel || '').toLowerCase());
const dataValid = !apiError && supportedChannel;

const today = extractMetrics(todayPayload.row);
const yesterday = extractMetrics(yesterdayPayload.row);

const variations = {
  spend: variation(today.spend, yesterday.spend),
  reach: variation(today.reach, yesterday.reach),
  impressions: variation(today.impressions, yesterday.impressions),
  clicks: variation(today.clicks, yesterday.clicks),
  ctr: variation(today.ctr, yesterday.ctr),
  cpc: variation(today.cpc, yesterday.cpc),
  cpm: variation(today.cpm, yesterday.cpm),
  conversions: variation(today.conversions, yesterday.conversions),
  cost_per_result: variation(today.cost_per_result, yesterday.cost_per_result),
  roas: variation(today.roas, yesterday.roas),
};

const noActivity = today.spend === 0 && today.impressions === 0 && today.reach === 0;
const periodLabel = new Date(`${client.report_date}T12:00:00Z`).toLocaleDateString('pt-BR', {
  timeZone: 'UTC',
});

let message;
if (noActivity) {
  message = `Olá, ${client.client_name}! 👋

📊 Relatório diário de campanhas — ${periodLabel}

Hoje não identificamos veiculação ou consumo de orçamento nas campanhas monitoradas da sua conta.

Isso pode ocorrer quando:
• as campanhas estão pausadas;
• o orçamento foi atingido;
• os anúncios estão em análise;
• não houve entrega no período.

Nossa equipe seguirá acompanhando e avisará caso seja necessário algum ajuste.

R2R Marketing Digital`;
} else {
  message = `Olá, ${client.client_name}! 👋

📊 Relatório diário de campanhas — ${periodLabel}

💰 Investimento: ${formatCurrency(today.spend, client.currency)} (${variations.spend.label})
👥 Alcance: ${formatNumber(today.reach)} (${variations.reach.label})
👁️ Impressões: ${formatNumber(today.impressions)} (${variations.impressions.label})
🖱️ Cliques: ${formatNumber(today.clicks)} (${variations.clicks.label})
📈 CTR: ${formatNumber(today.ctr, 2)}% (${variations.ctr.label})
💳 CPC: ${formatCurrency(today.cpc, client.currency)} (${variations.cpc.label})
📣 CPM: ${formatCurrency(today.cpm, client.currency)} (${variations.cpm.label})
🎯 Resultados: ${formatNumber(today.conversions)} (${variations.conversions.label})
💵 Custo por resultado: ${formatCurrency(today.cost_per_result, client.currency)} (${variations.cost_per_result.label})
📊 ROAS: ${formatNumber(today.roas, 2)}x (${variations.roas.label})

🔎 Comparativo realizado em relação ao dia anterior.
ℹ️ Os dados do Meta ads podem receber atualizações posteriores por causa da atribuição de conversões.

R2R Marketing Digital`;
}

return [{
  json: {
    ...client,
    data_valid: dataValid,
    api_error: apiError ? (apiError.message || JSON.stringify(apiError)) : (!supportedChannel ? `Canal não suportado: ${client.channel}` : null),
    no_activity: noActivity,
    metrics_today: today,
    metrics_yesterday: yesterday,
    variations,
    message,
    email_subject: `Relatório diário Meta ads — ${client.client_name} — ${periodLabel}`,
    delivery_status: noActivity ? 'no_activity' : 'sent',
  },
}];

const items = $input.all();
return [{
  json: {
    completed_at: new Date().toISOString(),
    processed_items: items.length,
    status: 'completed',
  },
}];
